private val _uiState = MutableStateFlow(SearchUiState())
val uiState: StateFlow<SearchUiState> = _uiState.asStateFlow()

fun onQueryChanged(query: String) {
    _uiState.update { old -> old.copy(query = query) }
}

// Dễ mất update nếu nhiều writer
_state.value = _state.value.copy(unread = _state.value.unread + 1)

// Atomic theo snapshot StateFlow
_state.update { old -> old.copy(unread = old.unread + 1) }

sealed interface JobDetailUiState {
    data object Loading : JobDetailUiState
    data class Content(val job: Job, val refreshing: Boolean) : JobDetailUiState
    data class Error(val message: UiText) : JobDetailUiState
}

val uiState: StateFlow<JobDetailUiState> = repository.observeJob(id)
    .map { job ->
        if (job == null) JobDetailUiState.Loading
        else JobDetailUiState.Content(job, refreshing = false)
    }
    .stateIn(
        scope = viewModelScope,
        started = SharingStarted.WhileSubscribed(5_000),
        initialValue = JobDetailUiState.Loading
    )

,
    val items: List<Job> = emptyList(),
    val loading: Boolean = false,
    val error: UiText? = null
)

private val _state = MutableStateFlow(SearchUiState())
val state = _state.asStateFlow()

fun reduce(result: SearchResult) {
    _state.update { old ->
        when (result) {
            is SearchResult.Started -> old.copy(loading = true, error = null)
            is SearchResult.Success -> old.copy(loading = false, items = result.items)
            is SearchResult.Failure -> old.copy(loading = false, error = result.message)
        }
    }
}

@Composable
fun SearchRoute(viewModel: SearchViewModel) {
    val state by viewModel.state.collectAsStateWithLifecycle()
    SearchScreen(state = state, onIntent = viewModel::onIntent)
}
